import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { BaseService } from './base.service';
import { Department } from '../models';

@Injectable({ providedIn: 'root' })
export class DepartmentsService extends BaseService<Department> {
  protected override tableName = 'departments';

  /**
   * Ottiene tutti i reparti di un'azienda.
   */
  getByCompany(companyId: string): Observable<Department[]> {
    return this.getAll(companyId);
  }

  /**
   * Crea un nuovo reparto.
   */
  createDepartment(department: Omit<Department, 'id' | 'created_at' | 'updated_at'>): Observable<Department> {
    return this.create(department);
  }

  /**
   * Aggiorna un reparto esistente.
   */
  updateDepartment(id: string, updates: Partial<Department>): Observable<Department> {
    return this.update(id, updates);
  }

  /**
   * Elimina un reparto (hard delete).
   */
  deleteDepartment(id: string): Observable<void> {
    return this.delete(id);
  }
}
